export function buildSeedProducts(): Product[] {
  const now = new Date().toISOString();
  return raw.map((p, i) => {
    const base = `${p.brand}-${p.classification}-${p.model}-${p.size}-${p.gender}`;
    const id = `p_${i.toString(36).padStart(4, '0')}_${slugify(base).slice(0, 40)}`;
    const slug = slugify(`${p.brand}-${p.model}-${p.size}-${p.classification === 'ORIGINAL' ? 'original' : 'alt'}`);
    return {
      ...p,
      id,
      slug,
      stock: p.stock ?? (Math.floor(Math.random() * 8) + 3),
      featured: p.featured ?? false,
      active: true,
      images: [],
      createdAt: now,
      updatedAt: now,
    } as Product;
  });
}
